import React, { useState, useEffect } from 'react';
import { Sun, Moon, Waves } from 'lucide-react';
import { Button } from '@/components/ui/button';

const THEMES = [
  { id: 'light', label: 'Light', icon: Sun },
  { id: 'dark', label: 'Dark', icon: Moon },
  { id: 'blue', label: 'Blue', icon: Waves },
];

export default function ThemeToggle() {
  const [theme, setTheme] = useState(() => localStorage.getItem('theme') || 'light');

  useEffect(() => {
    const root = document.documentElement;
    root.classList.remove('dark', 'blue');
    if (theme !== 'light') root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const cycle = () => {
    const idx = THEMES.findIndex(t => t.id === theme);
    setTheme(THEMES[(idx + 1) % THEMES.length].id);
  };

  const CurrentIcon = THEMES.find(t => t.id === theme)?.icon || Sun;
  return (
    <Button variant="ghost" size="icon" className="h-8 w-8" onClick={cycle} title={`Theme: ${theme}`}>
      <CurrentIcon className="w-4 h-4" />
    </Button>
  );
}

