import React from 'react';
import { formatTime } from '@/lib/srtParser';

const SOURCE_BADGES = {
  translate: { short: 'G', className: 'bg-blue-500/15 text-blue-600 dark:text-blue-400' },
  srt: { short: 'S', className: 'bg-green-500/15 text-green-600 dark:text-green-400' },
  both: { short: 'G+S', className: 'bg-purple-500/15 text-purple-600 dark:text-purple-400' },
  original: { short: 'O', className: 'bg-gray-500/15 text-gray-500' },
};

function renderWithHighlight(text, charIndex) {
  if (charIndex == null) return text;
  const regex = /\S+/g;
  let match;
  while ((match = regex.exec(text)) !== null) {
    const start = match.index;
    const end = start + match[0].length;
    if (charIndex >= start && charIndex < end) {
      return (
        <>
          {text.slice(0, start)}
          <mark className="bg-primary/25 text-foreground rounded px-0.5">{match[0]}</mark>
          {text.slice(end)}
        </>
      );
    }
  }
  return text;
}

const LAYOUTS = {
  stacked: {
    container: 'flex-col gap-1',
    text: 'flex-col gap-0.5',
    textSize: 'text-sm',
  },
  side: {
    container: 'flex-col gap-1',
    text: 'flex-row gap-2',
    textSize: 'text-sm',
  },
  compact: {
    container: 'flex-col gap-0',
    text: 'flex-col gap-0',
    textSize: 'text-xs',
  },
};

export default function SubtitleDisplay({
  segments, currentIndex, translations, languages,
  highlightState, layout = 'stacked', onSegmentClick, hideOriginal = false
}) {
  if (!segments || segments.length === 0) return null;

  const cur = currentIndex >= 0 ? currentIndex : 0;
  const start = Math.max(0, cur - 1);
  const end = Math.min(segments.length, start + 3);
  const adjustedStart = Math.max(0, end - 3);
  const visible = segments.slice(adjustedStart, end);
  const visibleIndices = Array.from({ length: end - adjustedStart }, (_, i) => adjustedStart + i);

  const enabledLangs = (languages || []).filter(l => l.enabled);
  const layoutClass = LAYOUTS[layout] || LAYOUTS.stacked;

  return (
    <div className="space-y-1">
      {visible.map((seg, i) => {
        const realIndex = visibleIndices[i];
        const isCurrent = realIndex === currentIndex || (currentIndex < 0 && i === 0);
        const isHighlighted = highlightState?.segIndex === realIndex;

        return (
          <button
            key={realIndex}
            onClick={() => onSegmentClick?.(realIndex)}
            className={`w-full text-left px-3 py-2 rounded-lg transition-all duration-200 block ${
              isCurrent
                ? 'bg-primary/10 border border-primary/30'
                : 'hover:bg-muted/60 border border-transparent'
            }`}
          >
            <div className="flex items-start gap-2">
              <span className="text-[10px] font-mono mt-0.5 shrink-0 px-1.5 py-0.5 rounded bg-muted text-muted-foreground">
                #{realIndex}
              </span>
              <span className="text-[10px] text-muted-foreground font-mono mt-1 shrink-0">
                {formatTime(seg.start)}
              </span>
              <div className={`flex-1 min-w-0 ${layoutClass.text}`}>
                {!hideOriginal && (
                  <p className={`${layoutClass.textSize} leading-relaxed ${isCurrent ? 'font-medium text-foreground' : 'text-muted-foreground'}`}>
                    {isHighlighted
                      ? renderWithHighlight(seg.text, highlightState.charIndex)
                      : seg.text}
                  </p>
                )}

                {/* Translations for all enabled languages */}
                {enabledLangs.map(lang => {
                  const translation = translations?.[`${lang.code}:${realIndex}`];
                  if (!translation) return null;
                  const badge = SOURCE_BADGES[translation.source] || SOURCE_BADGES.original;
                  return (
                    <div key={lang.code} className={`flex items-start gap-1.5 ${layout === 'side' ? 'flex-1' : ''}`}>
                      <span
                        className="w-2 h-2 rounded-full mt-1.5 shrink-0"
                        style={{ backgroundColor: lang.color }}
                      />
                      <span className={`text-[9px] font-mono px-1 rounded shrink-0 mt-1 ${badge.className}`}>
                        {badge.short}
                      </span>
                      <p className={`${layoutClass.textSize} ${isCurrent ? 'text-primary font-medium' : 'text-primary/60'}`}>
                        {translation.text}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          </button>
        );
      })}
    </div>
  );
}

