import React from 'react';
import { Button } from '@/components/ui/button';
import { X, Clock, History } from 'lucide-react';

export default function CachedVideos({ videos, onSelect, onRemove }) {
  if (!videos || videos.length === 0) return null;

  const formatTime = (ts) => {
    const diff = Date.now() - ts;
    const hrs = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);
    if (days > 0) return `${days}d ago`;
    if (hrs > 0) return `${hrs}h ago`;
    return 'recently';
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
        <History className="w-3.5 h-3.5" />
        <span>Cached videos</span>
      </div>
      {videos.map(v => (
        <div
          key={`${v.videoId}-${v.langCode}`}
          className="flex items-center gap-2 p-2.5 rounded-lg border bg-card hover:bg-muted/50 transition-colors cursor-pointer group"
          onClick={() => onSelect(v)}
        >
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium truncate">{v.title || v.videoId}</p>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="text-[10px] text-muted-foreground font-mono">{v.langCode}</span>
              <span className="text-[10px] text-muted-foreground flex items-center gap-0.5">
                <Clock className="w-2.5 h-2.5" /> {formatTime(v.timestamp)}
              </span>
            </div>
          </div>
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7 opacity-0 group-hover:opacity-100 transition-opacity"
            onClick={(e) => { e.stopPropagation(); onRemove(v); }}
          >
            <X className="w-3 h-3" />
          </Button>
        </div>
      ))}
    </div>
  );
}

