import React from 'react';
import { Button } from '@/components/ui/button';
import { Slider } from '@/components/ui/slider';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { X, Plus, Volume2, Languages } from 'lucide-react';
import { LANG_COLORS, getDefaultColor } from '@/lib/langUtils';

const COMMON_LANGUAGES = [
  { code: 'es', name: 'Spanish' },
  { code: 'fr', name: 'French' },
  { code: 'de', name: 'German' },
  { code: 'it', name: 'Italian' },
  { code: 'pt', name: 'Portuguese' },
  { code: 'ru', name: 'Russian' },
  { code: 'ja', name: 'Japanese' },
  { code: 'ko', name: 'Korean' },
  { code: 'zh-CN', name: 'Chinese (Simplified)' },
  { code: 'zh-TW', name: 'Chinese (Traditional)' },
  { code: 'ar', name: 'Arabic' },
  { code: 'hi', name: 'Hindi' },
  { code: 'tr', name: 'Turkish' },
  { code: 'pl', name: 'Polish' },
  { code: 'nl', name: 'Dutch' },
  { code: 'sv', name: 'Swedish' },
  { code: 'he', name: 'Hebrew' },
  { code: 'th', name: 'Thai' },
  { code: 'vi', name: 'Vietnamese' },
];

const SOURCE_OPTIONS = [
  { value: 'translate', label: 'Google' },
  { value: 'srt', label: 'SRT' },
  { value: 'both', label: 'Both' },
];

export default function LanguageConfig({ languages, onChange, srtErrors = {} }) {
  const addLanguage = () => {
    const used = new Set(languages.map(l => l.code));
    const next = COMMON_LANGUAGES.find(l => !used.has(l.code));
    if (next) {
      onChange([...languages, {
        code: next.code, name: next.name, ttsRate: 1.0, source: 'translate',
        enabled: true, color: getDefaultColor(languages.length)
      }]);
    }
  };

  const removeLanguage = (index) => {
    onChange(languages.filter((_, i) => i !== index));
  };

  const updateLanguage = (index, updates) => {
    onChange(languages.map((l, i) => i === index ? { ...l, ...updates } : l));
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Languages className="w-4 h-4 text-muted-foreground" />
          <span className="text-sm font-medium">Practice Languages</span>
        </div>
        <Button variant="ghost" size="sm" onClick={addLanguage} className="h-7 text-xs gap-1">
          <Plus className="w-3 h-3" /> Add
        </Button>
      </div>

      {languages.map((lang, i) => (
        <div key={i} className="rounded-lg border bg-card p-3 space-y-3">
          <div className="flex items-center gap-2">
            {/* Color circle — click to cycle */}
            <button
              className="w-5 h-5 rounded-full border-2 border-white shadow-sm shrink-0 ring-1 ring-black/10 cursor-pointer transition-transform hover:scale-110"
              style={{ backgroundColor: lang.color || getDefaultColor(i) }}
              onClick={() => {
                const currentIdx = LANG_COLORS.indexOf(lang.color);
                const nextColor = LANG_COLORS[(currentIdx + 1) % LANG_COLORS.length];
                updateLanguage(i, { color: nextColor });
              }}
              title="Click to change color"
            />

            <Select
              value={lang.code}
              onValueChange={(code) => {
                const found = COMMON_LANGUAGES.find(l => l.code === code);
                updateLanguage(i, { code, name: found?.name || code });
              }}
            >
              <SelectTrigger className="h-8 text-sm flex-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {COMMON_LANGUAGES.map(l => (
                  <SelectItem key={l.code} value={l.code}>{l.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Switch
              checked={lang.enabled}
              onCheckedChange={(enabled) => updateLanguage(i, { enabled })}
            />

            {languages.length > 1 && (
              <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => removeLanguage(i)}>
                <X className="w-3 h-3" />
              </Button>
            )}
          </div>

          {lang.enabled && (
            <>
              {/* TTS speed rate per language */}
              <div className="flex items-center gap-3">
                <Volume2 className="w-3.5 h-3.5 text-muted-foreground shrink-0" />
                <span className="text-xs text-muted-foreground w-12">TTS</span>
                <Slider
                  value={[lang.ttsRate]}
                  onValueChange={([v]) => updateLanguage(i, { ttsRate: v })}
                  min={0.3}
                  max={2.5}
                  step={0.1}
                  className="flex-1"
                />
                <span className="text-xs text-muted-foreground w-10 text-right">{lang.ttsRate.toFixed(1)}x</span>
              </div>

              {/* Source selector with SRT error indicator */}
              <div className="flex items-center gap-1 flex-wrap">
                <Label className="text-xs text-muted-foreground mr-1">Source:</Label>
                {SOURCE_OPTIONS.map(src => {
                  const isSelected = lang.source === src.value;
                  const hasError = src.value === 'srt' && srtErrors[lang.code];
                  return (
                    <button
                      key={src.value}
                      onClick={() => updateLanguage(i, { source: src.value })}
                      className={`px-2 py-0.5 rounded text-xs transition-colors ${
                        isSelected
                          ? hasError
                            ? 'bg-red-500 text-white'
                            : 'bg-primary text-primary-foreground'
                          : hasError
                            ? 'text-red-500 border border-red-500/50'
                            : 'bg-muted text-muted-foreground hover:bg-muted/80'
                      }`}
                    >
                      {src.label}
                      {hasError && ' ⚠'}
                    </button>
                  );
                })}
              </div>
            </>
          )}
        </div>
      ))}
    </div>
  );
}

