import React, { useState, useEffect } from 'react';
import { subscribe, getLogs, clearLogs } from '@/lib/logger';
import { Button } from '@/components/ui/button';
import { Trash2, Terminal, ChevronDown, ChevronUp } from 'lucide-react';

const TYPE_STYLES = {
  info: 'text-blue-500',
  error: 'text-red-500',
  warn: 'text-yellow-500',
  success: 'text-green-500',
};

const TYPE_PREFIX = {
  info: 'ℹ',
  error: '✖',
  warn: '⚠',
  success: '✓',
};

export default function ActivityLog() {
  const [logs, setLogs] = useState(getLogs());
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => subscribe(setLogs), []);

  const formatTs = (d) => {
    const ms = String(d.getMilliseconds()).padStart(3, '0');
    return d.toLocaleTimeString('en-US', { hour12: false }) + '.' + ms;
  };

  return (
    <div className="rounded-xl border bg-card overflow-hidden">
      <div className="flex items-center justify-between px-3 py-2 border-b bg-muted/30">
        <button
          onClick={() => setIsOpen(o => !o)}
          className="flex items-center gap-1.5 text-xs font-medium hover:text-foreground transition-colors"
        >
          <Terminal className="w-3.5 h-3.5 text-muted-foreground" />
          Activity Log
          <span className="text-[10px] text-muted-foreground font-normal">({logs.length})</span>
          {isOpen ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
        </button>
        {isOpen && logs.length > 0 && (
          <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => clearLogs()}>
            <Trash2 className="w-3 h-3" />
          </Button>
        )}
      </div>

      {isOpen && (
        <div className="max-h-[240px] overflow-y-auto p-2 space-y-0.5 font-mono text-[11px]">
          {logs.length === 0 ? (
            <p className="text-muted-foreground text-center py-4 text-xs">No events yet</p>
          ) : (
            [...logs].reverse().map(entry => (
              <div key={entry.id} className="flex gap-2 leading-relaxed">
                <span className="text-muted-foreground/60 shrink-0">{formatTs(entry.timestamp)}</span>
                <span className={`shrink-0 ${TYPE_STYLES[entry.type] || 'text-muted-foreground'}`}>
                  {TYPE_PREFIX[entry.type] || '•'}
                </span>
                <span className="text-foreground/90 break-words">{entry.message}</span>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}

