import React, { useEffect, useRef, useImperativeHandle, forwardRef, useCallback } from 'react';

const YouTubeEmbed = forwardRef(({ videoId, onStateChange, onTimeUpdate, onReady }, ref) => {
  const playerRef = useRef(null);
  const containerRef = useRef(null);
  const intervalRef = useRef(null);
  const readyRef = useRef(false);

  useImperativeHandle(ref, () => ({
    play: () => { if (readyRef.current) playerRef.current?.playVideo(); },
    pause: () => { if (readyRef.current) playerRef.current?.pauseVideo(); },
    seekTo: (seconds) => { if (readyRef.current) playerRef.current?.seekTo(seconds, true); },
    getCurrentTime: () => readyRef.current ? (playerRef.current?.getCurrentTime() || 0) : 0,
    setPlaybackRate: (rate) => { if (readyRef.current) playerRef.current?.setPlaybackRate(rate); },
    getPlayerState: () => readyRef.current ? playerRef.current?.getPlayerState() : -1,
    isReady: () => readyRef.current,
  }));

  const startTimeTracking = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(() => {
      if (playerRef.current?.getCurrentTime) {
        onTimeUpdate?.(playerRef.current.getCurrentTime());
      }
    }, 200);
  }, [onTimeUpdate]);

  const stopTimeTracking = useCallback(() => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (!videoId) return;
    readyRef.current = false;

    const loadPlayer = () => {
      if (playerRef.current?.destroy) {
        playerRef.current.destroy();
      }
      playerRef.current = new window.YT.Player(containerRef.current, {
        videoId,
        playerVars: {
          autoplay: 0,
          controls: 1,
          modestbranding: 1,
          rel: 0,
          cc_load_policy: 0,
        },
        events: {
          onReady: () => {
            readyRef.current = true;
            onReady?.();
          },
          onStateChange: (event) => {
            const state = event.data;
            if (state === window.YT.PlayerState.PLAYING) {
              startTimeTracking();
            } else {
              stopTimeTracking();
            }
            onStateChange?.(state);
          },
        },
      });
    };

    if (window.YT && window.YT.Player) {
      loadPlayer();
    } else {
      if (!document.getElementById('yt-iframe-api')) {
        const tag = document.createElement('script');
        tag.src = 'https://www.youtube.com/iframe_api';
        tag.id = 'yt-iframe-api';
        document.body.appendChild(tag);
      }
      window.onYouTubeIframeAPIReady = loadPlayer;
    }

    return () => {
      stopTimeTracking();
      readyRef.current = false;
      if (playerRef.current?.destroy) playerRef.current.destroy();
    };
  }, [videoId]);

  return (
    <div className="w-full aspect-video rounded-xl overflow-hidden bg-black/5">
      <div ref={containerRef} className="w-full h-full" />
    </div>
  );
});

YouTubeEmbed.displayName = 'YouTubeEmbed';
export default YouTubeEmbed;

