import React, { useState, useRef, useCallback, useEffect } from 'react';
import { extractVideoId, fetchSubtitles, fetchAvailableLanguages, fetchVideoTitle } from '@/lib/subtitleService';
import { parseSRT } from '@/lib/srtParser';
import { isAutoGenerated } from '@/lib/langUtils';
import { log } from '@/lib/logger';
import { isCacheEnabled, setCacheEnabledState, getCachedVideos, getCachedVideo, setCachedVideo, removeCachedVideo } from '@/lib/cache';
import SetupForm from '@/components/player/SetupForm';
import YouTubeEmbed from '@/components/player/YouTubeEmbed';
import SubtitleDisplay from '@/components/player/SubtitleDisplay';
import PlaybackControls from '@/components/player/PlaybackControls';
import LanguageConfig from '@/components/player/LanguageConfig';
import BaseLanguageSelector from '@/components/player/BaseLanguageSelector';
import ActivityLog from '@/components/player/ActivityLog';
import ThemeToggle from '@/components/ThemeToggle';
import useSyncEngine from '@/hooks/useSyncEngine';
import { useToast } from '@/components/ui/use-toast';
import { ArrowLeft, Settings, ChevronDown, ChevronUp, LayoutGrid, Share2, EyeOff, Eye } from 'lucide-react';
import { Button } from '@/components/ui/button';

const LAYOUT_OPTIONS = [
  { value: 'stacked', label: 'Stacked' },
  { value: 'side', label: 'Side' },
  { value: 'compact', label: 'Compact' },
];

function encodeLanguages(langs) {
  try { return btoa(encodeURIComponent(JSON.stringify(langs))); }
  catch { return ''; }
}

function decodeLanguages(str) {
  if (!str) return null;
  try { return JSON.parse(decodeURIComponent(atob(str))); }
  catch { return null; }
}

export default function Home() {
  const { toast } = useToast();
  const ytRef = useRef(null);

  const [videoId, setVideoId] = useState(null);
  const [videoTitle, setVideoTitle] = useState('');
  const [segments, setSegments] = useState([]);
  const [sourceLang, setSourceLang] = useState('en');
  const [availableLangs, setAvailableLangs] = useState([]);
  const [baseLang, setBaseLang] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [videoRate, setVideoRate] = useState(1);
  const [showSettings, setShowSettings] = useState(false);
  const [subtitleLayout, setSubtitleLayout] = useState('stacked');
  const [hideOriginal, setHideOriginal] = useState(false);
  const [cacheEnabled, setCacheEnabled] = useState(isCacheEnabled());
  const [cachedVideos, setCachedVideos] = useState(getCachedVideos());

  const [languages, setLanguages] = useState([
    { code: 'es', name: 'Spanish', ttsRate: 1.0, source: 'translate', enabled: true, color: '#3b82f6' },
  ]);

  const engine = useSyncEngine({ segments, sourceLang, languages, ytRef });

  const loadVideoData = useCallback(async (id, langCode, title) => {
    // Check cache first
    if (isCacheEnabled()) {
      const cached = getCachedVideo(id, langCode);
      if (cached?.segments?.length) {
        log('info', `Loaded from cache: ${id} (${langCode})`);
        setSegments(cached.segments);
        return cached.segments;
      }
    }

    // Fetch from API
    log('info', `Fetching subtitles (lang=${langCode})…`);
    const srtText = await fetchSubtitles(id, langCode);
    const parsed = parseSRT(srtText);
    log('success', `Parsed ${parsed.length} subtitle segments`);

    if (parsed.length === 0) {
      throw new Error('No subtitle segments found');
    }

    setSegments(parsed);

    // Cache it
    if (isCacheEnabled()) {
      setCachedVideo({ videoId: id, langCode, title, segments: parsed });
      setCachedVideos(getCachedVideos());
    }

    return parsed;
  }, []);

  const handleStart = useCallback(async (input, opts = {}) => {
    const id = extractVideoId(input);
    if (!id) {
      toast({ title: 'Invalid input', description: 'Please enter a valid YouTube URL or video ID.', variant: 'destructive' });
      return;
    }

    setIsLoading(true);
    log('info', `Loading video: ${id}`);
    try {
      // Fetch title and available languages in parallel
      const [title, langs] = await Promise.all([
        fetchVideoTitle(id),
        fetchAvailableLanguages(id),
      ]);
      setVideoTitle(title);
      setAvailableLangs(langs);
      log('success', `Video: "${title}", ${langs.length} languages available`);

      // Select default language (prefer _auto)
      const autoLang = langs.find(l => isAutoGenerated(l.code)) ||
                       langs.find(l => l.isDefault) ||
                       langs[0];
      const selectedLang = opts.lang || autoLang?.code || 'en_auto';
      setBaseLang(selectedLang);
      setSourceLang(selectedLang);
      log('info', `Base language: ${selectedLang}`);

      if (opts.languages) setLanguages(opts.languages);
      if (opts.layout) setSubtitleLayout(opts.layout);
      if (opts.rate) setVideoRate(opts.rate);

      await loadVideoData(id, selectedLang, title);

      setVideoId(id);

      // Load SRT for languages that use it
      const langsToUse = opts.languages || languages;
      for (const lang of langsToUse) {
        if (lang.source === 'srt' || lang.source === 'both') {
          engine.loadSRT(id, lang.code);
        }
      }
    } catch (err) {
      log('error', `Failed to load video: ${err.message}`);
      toast({ title: 'Error loading video', description: err.message, variant: 'destructive' });
    }
    setIsLoading(false);
  }, [languages, toast, engine, loadVideoData]);

  const handleBaseLangChange = useCallback(async (newLang) => {
    if (!videoId || newLang === baseLang) return;
    setBaseLang(newLang);
    setSourceLang(newLang);
    // Stop playback
    if (engine.isActive) engine.togglePlayPause();
    log('info', `Switching base language to ${newLang}`);

    try {
      await loadVideoData(videoId, newLang, videoTitle);
    } catch (err) {
      log('error', `Failed to switch language: ${err.message}`);
      toast({ title: 'Failed to load subtitles', description: err.message, variant: 'destructive' });
    }
  }, [videoId, baseLang, videoTitle, engine, loadVideoData, toast]);

  const handleSelectCached = useCallback(async (video) => {
    const id = video.videoId;
    const langCode = video.langCode;
    log('info', `Loading cached video: ${video.title}`);

    setVideoId(id);
    setVideoTitle(video.title);
    setBaseLang(langCode);
    setSourceLang(langCode);

    const cached = getCachedVideo(id, langCode);
    if (cached?.segments?.length) {
      setSegments(cached.segments);
    }

    // Fetch available languages in background
    fetchAvailableLanguages(id).then(langs => setAvailableLangs(langs)).catch(() => {});

    // Load SRT for languages that use it
    for (const lang of languages) {
      if (lang.source === 'srt' || lang.source === 'both') {
        engine.loadSRT(id, lang.code);
      }
    }
  }, [languages, engine]);

  const handleRemoveCached = useCallback((video) => {
    removeCachedVideo(video.videoId, video.langCode);
    setCachedVideos(getCachedVideos());
  }, []);

  const handleToggleCache = useCallback((enabled) => {
    setCacheEnabled(enabled);
    setCacheEnabledState(enabled);
    if (enabled) setCachedVideos(getCachedVideos());
  }, []);

  const handleVideoRateChange = useCallback((rate) => {
    setVideoRate(rate);
    ytRef.current?.setPlaybackRate(rate);
    log('info', `Video speed set to ${rate}x`);
  }, [ytRef]);

  const handleSegmentClick = useCallback((idx) => {
    engine.goToSegment(idx);
  }, [engine]);

  // Reload SRTs when languages change
  useEffect(() => {
    if (!videoId) return;
    for (const lang of languages) {
      if (lang.source === 'srt' || lang.source === 'both') {
        engine.loadSRT(videoId, lang.code);
      }
    }
  }, [languages, videoId]);

  // Auto-load from URL params on mount
  const autoStartRef = useRef(false);
  useEffect(() => {
    if (autoStartRef.current) return;
    autoStartRef.current = true;
    const params = new URLSearchParams(window.location.search);
    const v = params.get('v');
    if (!v) return;
    handleStart(v, {
      lang: params.get('lang') || undefined,
      languages: decodeLanguages(params.get('langs')),
      layout: params.get('layout') || undefined,
      rate: params.get('rate') ? parseFloat(params.get('rate')) : undefined,
    });
  }, [handleStart]);

  // Sync state to URL params
  useEffect(() => {
    if (!videoId) return;
    const params = new URLSearchParams();
    params.set('v', videoId);
    if (baseLang) params.set('lang', baseLang);
    if (languages.length) params.set('langs', encodeLanguages(languages));
    if (subtitleLayout !== 'stacked') params.set('layout', subtitleLayout);
    if (videoRate !== 1) params.set('rate', String(videoRate));
    if (engine.currentIndex >= 0) params.set('seg', String(engine.currentIndex));
    window.history.replaceState(null, '', `${window.location.pathname}?${params.toString()}`);
  }, [videoId, baseLang, languages, subtitleLayout, videoRate, engine.currentIndex]);

  const handleShare = useCallback(async () => {
    const url = window.location.href;
    try {
      await navigator.clipboard.writeText(url);
      toast({ title: 'Link copied!', description: 'Share this URL to reproduce this state.' });
    } catch {
      window.prompt('Copy this URL:', url);
    }
  }, [toast]);

  const handleReset = useCallback(() => {
    if (engine.isActive) engine.togglePlayPause();
    setVideoId(null);
    setSegments([]);
    setAvailableLangs([]);
    setBaseLang(null);
    window.history.replaceState(null, '', window.location.pathname);
    log('info', 'Reset — returning to setup screen');
  }, [engine]);

  // Setup screen
  if (!videoId) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4 py-12 bg-gradient-to-b from-background to-muted/30">
        <div className="absolute top-4 right-4">
          <ThemeToggle />
        </div>
        <SetupForm
          onStart={handleStart}
          isLoading={isLoading}
          cachedVideos={cachedVideos}
          onSelectCached={handleSelectCached}
          onRemoveCached={handleRemoveCached}
          cacheEnabled={cacheEnabled}
          onToggleCache={handleToggleCache}
        />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-10 bg-background/80 backdrop-blur border-b px-4 py-2 flex items-center justify-between">
        <Button variant="ghost" size="sm" onClick={handleReset} className="gap-1 text-xs max-w-[40%]">
          <ArrowLeft className="w-3.5 h-3.5 shrink-0" />
          <span className="truncate">{videoTitle || 'New Video'}</span>
        </Button>
        <span className="text-xs font-mono text-muted-foreground hidden sm:inline">{videoId}</span>
        <div className="flex items-center gap-1">
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={handleShare} title="Share">
            <Share2 className="w-4 h-4" />
          </Button>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setShowSettings(s => !s)}>
            <Settings className="w-4 h-4" />
          </Button>
          <ThemeToggle />
        </div>
      </header>

      <div className="max-w-3xl mx-auto px-4 py-4 space-y-4">
        <YouTubeEmbed
          ref={ytRef}
          videoId={videoId}
          onStateChange={engine.handleYTStateChange}
          onTimeUpdate={engine.handleTimeUpdate}
          onReady={engine.handleReady}
        />

        <PlaybackControls
          isPlaying={engine.isActive}
          onPlayPause={engine.togglePlayPause}
          onPrev={engine.goPrev}
          onNext={engine.goNext}
          videoRate={videoRate}
          onVideoRateChange={handleVideoRateChange}
          currentSegment={engine.currentIndex}
          totalSegments={segments.length}
        />

        {/* Base language selector */}
        {availableLangs.length > 0 && (
          <BaseLanguageSelector
            languages={availableLangs}
            selected={baseLang}
            onChange={handleBaseLangChange}
          />
        )}

        <div>
          <button
            onClick={() => setShowSettings(s => !s)}
            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors w-full"
          >
