          </button>
          {showSettings && (
            <div className="mt-2 p-3 rounded-xl border bg-card">
              <LanguageConfig languages={languages} onChange={setLanguages} srtErrors={engine.srtErrors} />
            </div>
          )}
        </div>

        {/* Subtitle display with layout selector */}
        <div className="rounded-xl border bg-card p-3">
          <div className="flex items-center justify-between mb-2">
            <button
              onClick={() => setHideOriginal(h => !h)}
              className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
            >
              {hideOriginal ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
              {hideOriginal ? 'Show original' : 'Hide original'}
            </button>
            <div className="flex items-center gap-1">
              <LayoutGrid className="w-3 h-3 text-muted-foreground" />
              {LAYOUT_OPTIONS.map(opt => (
                <button
                  key={opt.value}
                  onClick={() => setSubtitleLayout(opt.value)}
                  className={`px-2 py-0.5 rounded text-[10px] transition-colors ${
                    subtitleLayout === opt.value
                      ? 'bg-primary text-primary-foreground'
                      : 'bg-muted text-muted-foreground hover:bg-muted/80'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>
          <SubtitleDisplay
            segments={segments}
            currentIndex={engine.currentIndex}
            translations={engine.translations}
            languages={languages}
            highlightState={engine.highlightState}
            layout={subtitleLayout}
            onSegmentClick={handleSegmentClick}
            hideOriginal={hideOriginal}
          />
        </div>

        <ActivityLog />
      </div>
    </div>
  );
}

