import { useState, useRef, useCallback, useEffect } from 'react';
import { findSegmentAtTime } from '@/lib/srtParser';
import { createTranslationCache } from '@/lib/translateService';
import { speak, stopSpeaking, requestWakeLock, releaseWakeLock } from '@/lib/ttsEngine';
import { fetchSubtitles } from '@/lib/subtitleService';
import { parseSRT } from '@/lib/srtParser';
import { log } from '@/lib/logger';

export default function useSyncEngine({ segments, sourceLang, languages, ytRef }) {
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isActive, setIsActive] = useState(false);
  const [translations, setTranslations] = useState({});
  const [activeTTSLang, setActiveTTSLang] = useState(null);
  const [highlightState, setHighlightState] = useState(null);
  const [srtErrors, setSrtErrors] = useState({});

  const cacheRef = useRef({});
  const srtCacheRef = useRef({});
  const translationsRef = useRef({});
  const isPlayingTTS = useRef(false);
  const abortRef = useRef(false);
  const isActiveRef = useRef(false);
  const playerReadyRef = useRef(false);

  useEffect(() => { translationsRef.current = translations; }, [translations]);

  // Build translation caches when languages/source change
  useEffect(() => {
    if (!segments?.length) return;
    const enabledLangs = languages.filter(l => l.enabled);
    const newCaches = {};
    enabledLangs.forEach(lang => {
      if (lang.source === 'translate' || lang.source === 'both') {
        if (!cacheRef.current[lang.code] || cacheRef.current[lang.code]._fromLang !== sourceLang) {
          const c = createTranslationCache(segments, sourceLang, lang.code);
          c._fromLang = sourceLang;
          newCaches[lang.code] = c;
        } else {
          newCaches[lang.code] = cacheRef.current[lang.code];
        }
      }
    });
    cacheRef.current = newCaches;
  }, [segments, languages, sourceLang]);

  const getTranslation = useCallback(async (segIndex, lang) => {
    const key = `${lang.code}:${segIndex}`;
    if (translationsRef.current[key]) return translationsRef.current[key];

    let text = '';
    let source = lang.source;

    if (lang.source === 'srt' || lang.source === 'both') {
      if (srtCacheRef.current[lang.code]) {
        const srtSeg = srtCacheRef.current[lang.code][segIndex];
        if (srtSeg?.text) text = srtSeg.text;
      }
    }

    if (lang.source === 'translate' || lang.source === 'both') {
      if (cacheRef.current[lang.code]) {
        const translated = await cacheRef.current[lang.code].get(segIndex);
        if (lang.source === 'both' && text) {
          text = `${text} | ${translated}`;
        } else if (!text) {
          text = translated;
        }
      }
    }

    if (!text) {
      text = segments[segIndex]?.text || '';
      source = 'original';
    }

    const result = { text, source };
    translationsRef.current[key] = result;
    setTranslations(prev => ({ ...prev, [key]: result }));
    return result;
  }, [segments]);

  // Clear and re-prefetch translations when language config changes
  useEffect(() => {
    if (!segments?.length) return;
    translationsRef.current = {};
    setTranslations({});
    if (currentIndex >= 0) {
      const enabledLangs = languages.filter(l => l.enabled);
      for (let i = Math.max(0, currentIndex - 1); i <= Math.min(segments.length - 1, currentIndex + 1); i++) {
        enabledLangs.forEach(lang => { getTranslation(i, lang); });
      }
    }
  }, [languages]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadSRT = useCallback(async (videoId, langCode) => {
    if (srtCacheRef.current[langCode] || srtErrors[langCode]) return;
    try {
      log('info', `Fetching SRT for language: ${langCode}`);
      const srtText = await fetchSubtitles(videoId, langCode);
      const parsed = parseSRT(srtText);
      if (parsed.length === 0) {
        setSrtErrors(prev => ({ ...prev, [langCode]: true }));
        log('warn', `SRT empty for ${langCode}`);
      } else {
        srtCacheRef.current[langCode] = parsed;
        setSrtErrors(prev => ({ ...prev, [langCode]: false }));
        log('success', `Loaded ${parsed.length} SRT segments for ${langCode}`);
      }
    } catch (err) {
      setSrtErrors(prev => ({ ...prev, [langCode]: true }));
      log('warn', `SRT not available for ${langCode}: ${err.message}`);
    }
  }, [srtErrors]);

  const playSegmentTTS = useCallback(async (segIndex) => {
    if (abortRef.current) return;
    isPlayingTTS.current = true;

    const enabledLangs = languages.filter(l => l.enabled);

    for (const lang of enabledLangs) {
      if (abortRef.current) break;
      setActiveTTSLang(lang.code);
      const result = await getTranslation(segIndex, lang);
      if (abortRef.current) break;
      log('info', `TTS [${lang.code}] segment ${segIndex}: "${result.text.slice(0, 60)}${result.text.length > 60 ? '…' : ''}"`, { rate: lang.ttsRate, source: result.source });
      try {
        await speak(result.text, lang.code, lang.ttsRate, (boundary) => {
          setHighlightState({ segIndex, langCode: lang.code, charIndex: boundary.charIndex });
        });
      } catch (err) {
        log('error', `TTS failed for ${lang.code}: ${err.message || err.error || err}`);
      }
    }

    isPlayingTTS.current = false;
    setActiveTTSLang(null);
    setHighlightState(null);
  }, [languages, getTranslation]);

  const startFromSegment = useCallback(async (segIndex) => {
    if (!segments?.length) {
      log('error', 'Cannot start: no segments loaded');
      return;
    }
    if (!playerReadyRef.current) {
      log('error', 'Cannot start: YouTube player not ready');
      return;
    }

    abortRef.current = true;
    stopSpeaking();
    await new Promise(r => setTimeout(r, 200));

    abortRef.current = false;
    isActiveRef.current = true;
    setIsActive(true);
    requestWakeLock();
    log('info', `▶ Sync started from segment ${segIndex}`);

    let idx = segIndex;

    while (idx < segments.length && !abortRef.current) {
      const seg = segments[idx];
      setCurrentIndex(idx);
      log('info', `Segment ${idx}: video playing [${seg.start.toFixed(1)}s → ${seg.end.toFixed(1)}s]`, { text: seg.text.slice(0, 80) });

      ytRef.current.seekTo(seg.start);
      ytRef.current.play();

      await new Promise((resolve) => {
        const check = setInterval(() => {
          if (abortRef.current) { clearInterval(check); resolve(); return; }
          const t = ytRef.current?.getCurrentTime() || 0;
          if (t >= seg.end - 0.15) { clearInterval(check); resolve(); }
        }, 100);
      });

      if (abortRef.current) break;

      ytRef.current.pause();
      log('info', `Segment ${idx}: video paused, starting TTS`);
      await playSegmentTTS(idx);

      if (abortRef.current) break;
      idx++;
    }

    if (!abortRef.current) {
      log('success', '⏹ Playback complete');
    }
    isActiveRef.current = false;
    setIsActive(false);
    releaseWakeLock();
  }, [segments, ytRef, playSegmentTTS]);

  const handleTimeUpdate = useCallback((time) => {
    if (isActiveRef.current || isPlayingTTS.current || !segments?.length) return;
    const idx = findSegmentAtTime(segments, time);
    if (idx >= 0 && idx !== currentIndex) {
      setCurrentIndex(idx);
    }
  }, [segments, currentIndex]);

  const handleYTStateChange = useCallback((state) => {
    const stateNames = { '-1': 'unstarted', '0': 'ended', '1': 'playing', '2': 'paused', '3': 'buffering', '5': 'cued' };
    log('info', `YouTube state: ${stateNames[state] || state}`);

    if (state === 1 && !isActiveRef.current && !isPlayingTTS.current && segments?.length && playerReadyRef.current) {
      const time = ytRef.current?.getCurrentTime() || 0;
      let idx = findSegmentAtTime(segments, time);
      if (idx < 0) {
        idx = segments.findIndex(s => s.start >= time);
        if (idx < 0) idx = 0;
      }
      log('info', `↩ Backward sync at ${time.toFixed(1)}s → segment ${idx}`);
      startFromSegment(idx);
    }
  }, [segments, ytRef, startFromSegment]);

  const handleReady = useCallback(() => {
    playerReadyRef.current = true;
    log('success', 'YouTube player ready');
  }, []);

  const togglePlayPause = useCallback(() => {
    if (isActiveRef.current) {
      abortRef.current = true;
      stopSpeaking();
      ytRef.current?.pause();
      isActiveRef.current = false;
      setIsActive(false);
      releaseWakeLock();
      log('info', '⏸ Playback stopped');
    } else {
      const start = currentIndex >= 0 ? currentIndex : 0;
      startFromSegment(start);
    }
  }, [currentIndex, startFromSegment, ytRef]);

  const goToSegment = useCallback((idx) => {
    log('info', `Jumping to segment ${idx}`);
    startFromSegment(idx);
  }, [startFromSegment]);

  const goNext = useCallback(() => {
    const next = Math.min((currentIndex >= 0 ? currentIndex : 0) + 1, segments.length - 1);
    goToSegment(next);
  }, [currentIndex, segments, goToSegment]);

  const goPrev = useCallback(() => {
    const prev = Math.max((currentIndex >= 0 ? currentIndex : 0) - 1, 0);
    goToSegment(prev);
  }, [currentIndex, segments, goToSegment]);

  return {
    currentIndex,
    isActive,
    translations,
    activeTTSLang,
    highlightState,
    srtErrors,
    handleTimeUpdate,
    handleYTStateChange,
    handleReady,
    togglePlayPause,
    goToSegment,
    goNext,
    goPrev,
    loadSRT,
  };
}

