// Simple activity logger with subscribe/notify pattern

let logs = [];
const listeners = new Set();

export function log(type, message, data) {
  const entry = {
    id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    timestamp: new Date(),
    type, // 'info' | 'error' | 'warn' | 'success'
    message,
    data,
  };
  logs = [...logs.slice(-199), entry]; // keep last 200
  listeners.forEach(fn => fn(logs));

  const ts = entry.timestamp.toLocaleTimeString('en-US', { hour12: false }) + '.' + String(entry.timestamp.getMilliseconds()).padStart(3, '0');
  if (type === 'error') console.error(`[${ts}]`, message, data ?? '');
  else if (type === 'warn') console.warn(`[${ts}]`, message, data ?? '');
  else console.log(`[${ts}]`, message, data ?? '');

  return entry;
}

// Auto-install global error handlers so any error in the app is logged
if (typeof window !== 'undefined') {
  window.addEventListener('error', (event) => {
    log('error', `Uncaught: ${event.message}`, { file: event.filename, line: event.lineno });
  });
  window.addEventListener('unhandledrejection', (event) => {
    const reason = event.reason;
    const msg = reason?.message || (typeof reason === 'string' ? reason : 'Unknown rejection');
    log('error', `Unhandled rejection: ${msg}`, reason?.stack || '');
  });
}

export function getLogs() { return logs; }
export function clearLogs() { logs = []; listeners.forEach(fn => fn(logs)); }
export function subscribe(fn) { listeners.add(fn); return () => listeners.delete(fn); }

