// Parse SRT text into structured segments
export function parseSRT(srtText) {
  if (!srtText || typeof srtText !== 'string') return [];
  const segments = [];
  const blocks = srtText.trim().split(/\n\s*\n/);

  for (const block of blocks) {
    const lines = block.trim().split('\n');
    if (lines.length < 2) continue;

    const timeMatch = lines.find(l => l.includes('-->'));
    if (!timeMatch) continue;

    const [startStr, endStr] = timeMatch.split('-->').map(s => s.trim());
    const textLines = lines.slice(lines.indexOf(timeMatch) + 1);
    const text = textLines.join(' ').replace(/<[^>]*>/g, '').trim();

    if (!text) continue;

    segments.push({
      start: timeToSeconds(startStr),
      end: timeToSeconds(endStr),
      text,
    });
  }

  return segments;
}

function timeToSeconds(timeStr) {
  // Format: HH:MM:SS,mmm or HH:MM:SS.mmm or MM:SS,mmm
  const cleaned = timeStr.replace(',', '.').trim();
  const parts = cleaned.split(':');
  if (parts.length === 3) {
    return (parseFloat(parts[0]) || 0) * 3600 + (parseFloat(parts[1]) || 0) * 60 + (parseFloat(parts[2]) || 0);
  }
  if (parts.length === 2) {
    return (parseFloat(parts[0]) || 0) * 60 + (parseFloat(parts[1]) || 0);
  }
  return parseFloat(parts[0]) || 0;
}

export function findSegmentAtTime(segments, timeSec) {
  return segments.findIndex(seg => timeSec >= seg.start && timeSec < seg.end);
}

export function formatTime(seconds) {
  if (typeof seconds !== 'number' || isNaN(seconds)) return '0:00';
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

