const VIDEOS_KEY = 'langsync:cached_videos';
const DATA_PREFIX = 'langsync:video:';
const ENABLED_KEY = 'langsync:cache_enabled';

export function isCacheEnabled() {
  return localStorage.getItem(ENABLED_KEY) !== 'false';
}

export function setCacheEnabledState(enabled) {
  localStorage.setItem(ENABLED_KEY, enabled ? 'true' : 'false');
}

export function getCachedVideos() {
  try { return JSON.parse(localStorage.getItem(VIDEOS_KEY) || '[]'); }
  catch { return []; }
}

export function getCachedVideo(videoId, langCode) {
  try {
    return JSON.parse(localStorage.getItem(`${DATA_PREFIX}${videoId}:${langCode}`));
  } catch { return null; }
}

export function setCachedVideo(data) {
  if (!isCacheEnabled()) return;
  const { videoId, langCode } = data;
  if (!videoId || !langCode) return;
  const ts = Date.now();
  localStorage.setItem(`${DATA_PREFIX}${videoId}:${langCode}`, JSON.stringify({ ...data, timestamp: ts }));

  const videos = getCachedVideos();
  const idx = videos.findIndex(v => v.videoId === videoId && v.langCode === langCode);
  const entry = { videoId, langCode, title: data.title, timestamp: ts };
  if (idx >= 0) videos[idx] = entry;
  else videos.push(entry);
  localStorage.setItem(VIDEOS_KEY, JSON.stringify(videos));
}

export function removeCachedVideo(videoId, langCode) {
  localStorage.removeItem(`${DATA_PREFIX}${videoId}:${langCode}`);
  const videos = getCachedVideos().filter(v => !(v.videoId === videoId && v.langCode === langCode));
  localStorage.setItem(VIDEOS_KEY, JSON.stringify(videos));
}

export function clearAllCache() {
  const videos = getCachedVideos();
  videos.forEach(v => localStorage.removeItem(`${DATA_PREFIX}${v.videoId}:${v.langCode}`));
  localStorage.removeItem(VIDEOS_KEY);
}

