import { stripAutoSuffix } from '@/lib/langUtils';

let currentUtterance = null;
let audioContext = null;

function ensureAudioContext() {
  if (!audioContext) {
    audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const osc = audioContext.createOscillator();
    const gain = audioContext.createGain();
    gain.gain.value = 0;
    osc.connect(gain);
    gain.connect(audioContext.destination);
    osc.start();
  }
  if (audioContext.state === 'suspended') {
    audioContext.resume();
  }
}

export function speak(text, lang = 'en', rate = 1.0, onBoundary) {
  return new Promise((resolve, reject) => {
    if (!window.speechSynthesis) {
      reject(new Error('Speech synthesis not supported'));
      return;
    }

    ensureAudioContext();
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    // Strip _auto suffix so TTS engine matches the correct voice
    const cleanLang = stripAutoSuffix(lang);
    utterance.lang = cleanLang;
    utterance.rate = Math.max(0.1, Math.min(10, rate));

    const voices = window.speechSynthesis.getVoices();
    const langVoice = voices.find(v => v.lang.startsWith(cleanLang)) ||
                      voices.find(v => v.lang.startsWith(cleanLang.split('-')[0]));
    if (langVoice) utterance.voice = langVoice;

    if (onBoundary) {
      utterance.onboundary = (event) => {
        if (event.name === 'word') {
          onBoundary({ charIndex: event.charIndex, charLength: event.charLength || 0 });
        }
      };
    }

    utterance.onend = () => { currentUtterance = null; resolve(); };
    utterance.onerror = (e) => {
      currentUtterance = null;
      if (e.error === 'canceled' || e.error === 'interrupted') resolve();
      else reject(e);
    };

    currentUtterance = utterance;
    window.speechSynthesis.speak(utterance);
  });
}

export function stopSpeaking() {
  if (window.speechSynthesis) {
    window.speechSynthesis.cancel();
  }
  currentUtterance = null;
}

export function isSpeaking() {
  return window.speechSynthesis?.speaking || false;
}

let wakeLock = null;

export async function requestWakeLock() {
  if ('wakeLock' in navigator) {
    try {
      wakeLock = await navigator.wakeLock.request('screen');
      wakeLock.addEventListener('release', () => { wakeLock = null; });
    } catch (e) {
      // Wake lock not available
    }
  }
}

export function releaseWakeLock() {
  if (wakeLock) {
    wakeLock.release();
    wakeLock = null;
  }
}

