import { stripAutoSuffix, isAutoGenerated } from '@/lib/langUtils';

const BASE_URL = 'https://youtube-dl-jrte.onrender.com/api';

export function extractVideoId(input) {
  if (!input) return null;
  const trimmed = input.trim();
  if (/^[a-zA-Z0-9_-]{11}$/.test(trimmed)) return trimmed;
  const patterns = [
    /(?:youtube\.com\/watch\?.*v=)([a-zA-Z0-9_-]{11})/,
    /(?:youtu\.be\/)([a-zA-Z0-9_-]{11})/,
    /(?:youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/,
    /(?:youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,
  ];
  for (const p of patterns) {
    const m = trimmed.match(p);
    if (m) return m[1];
  }
  return null;
}

export async function fetchSubtitles(videoId, language = 'en') {
  // Strip _auto suffix — the subtitle API expects plain language codes
  const cleanLang = stripAutoSuffix(language);
  const url = `${BASE_URL}/subtitles?url=${encodeURIComponent(videoId)}&type=srt&language=${encodeURIComponent(cleanLang)}&download=1`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch subtitles: ${res.status}`);
  const text = await res.text();

  const trimmed = text.trim();
  if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
    try {
      const json = JSON.parse(trimmed);
      if (typeof json === 'string') return json;
      return json.content || json.subtitle || json.text || json.data || json.body || json.srt || '';
    } catch {
      // Not valid JSON — return raw
    }
  }
  return text;
}

export async function fetchSupportedLanguages(videoId) {
  const url = `${BASE_URL}/transcript-supported-languages?videoID=${encodeURIComponent(videoId)}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch languages: ${res.status}`);
  return res.json();
}

export async function fetchDefaultLanguages(videoId) {
  const url = `${BASE_URL}/default-transcript-languages?videoID=${encodeURIComponent(videoId)}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch default languages: ${res.status}`);
  return res.json();
}

export async function fetchVideoTitle(videoId) {
  try {
    const res = await fetch(`https://www.youtube.com/oembed?url=https://www.youtube.com/watch?v=${videoId}&format=json`);
    if (res.ok) {
      const data = await res.json();
      return data.title || videoId;
    }
  } catch {
    // Fallback
  }
  return videoId;
}

// Extract language entries from various possible API response shapes
function extractLangs(data) {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  if (Array.isArray(data.languages)) return data.languages;
  if (Array.isArray(data.tracks)) return data.tracks;
  if (Array.isArray(data.subtitles)) return data.subtitles;
  return [];
}

function normalizeLangEntry(item) {
  if (!item) return null;
  if (typeof item === 'string') return { code: item, name: item };
  const code = item.code || item.language || item.lang;
  if (!code) return null;
  const name = item.name || item.label || item.language_name || code;
  const auto = item.auto || item.is_auto || item.auto_generated || isAutoGenerated(code);
  return { code, name, auto };
}

// Fetch and normalize all available languages for a video
export async function fetchAvailableLanguages(videoId) {
  const [defaults, supported] = await Promise.allSettled([
    fetchDefaultLanguages(videoId),
    fetchSupportedLanguages(videoId),
  ]);

  const defaultRaw = defaults.status === 'fulfilled' ? extractLangs(defaults.value) : [];
  const supportedRaw = supported.status === 'fulfilled' ? extractLangs(supported.value) : [];

  const result = [];
  const seen = new Set();

  // Process defaults first (mark as default)
  defaultRaw.forEach(item => {
    const entry = normalizeLangEntry(item);
    if (entry && !seen.has(entry.code)) {
      seen.add(entry.code);
      result.push({ ...entry, isDefault: true });
    }
  });

  // Then supported
  supportedRaw.forEach(item => {
    const entry = normalizeLangEntry(item);
    if (entry && !seen.has(entry.code)) {
      seen.add(entry.code);
      result.push({ ...entry, isDefault: false });
    }
  });

  if (result.length === 0) {
    result.push({ code: 'en_auto', name: 'English', auto: true, isDefault: true });
  }

  return result;
}

