import { stripAutoSuffix } from '@/lib/langUtils';

const langMap = {
  'zh-CN': 'zh-CN', 'zh-TW': 'zh-TW',
};

function normalizeLanguage(lang) {
  const stripped = stripAutoSuffix(lang);
  return langMap[stripped] || stripped.split('-')[0];
}

export async function translateText(text, fromLang, toLang) {
  const sl = normalizeLanguage(fromLang);
  const tl = normalizeLanguage(toLang);
  if (sl === tl) return text;

  const url = `https://translate.googleapis.com/translate_a/single?client=gtx&sl=${sl}&tl=${tl}&dt=t&q=${encodeURIComponent(text)}`;
  const res = await fetch(url);
  const data = await res.json();
  const translated = data?.translatedText || (data?.[0]?.[0]?.[0]) || '';
  if (!translated) throw new Error('No translated text returned');
  return translated;
}

export function createTranslationCache(segments, fromLang, toLang) {
  const cache = new Map();

  async function prefetch(startIndex, count = 5) {
    const end = Math.min(startIndex + count, segments.length);
    const promises = [];
    for (let i = startIndex; i < end; i++) {
      if (!cache.has(i)) {
        const idx = i;
        const p = translateText(segments[idx].text, fromLang, toLang)
          .then(t => cache.set(idx, t))
          .catch(() => cache.set(idx, segments[idx].text));
        promises.push(p);
      }
    }
    await Promise.all(promises);
  }

  return {
    async get(index) {
      if (!cache.has(index)) {
        await prefetch(index, 5);
      }
      prefetch(index + 1, 5);
      return cache.get(index) || segments[index]?.text || '';
    },
    prefetch,
    clear() { cache.clear(); },
  };
}

